const http = require('http');
const https = require('https');
const url = require('url');
const fs = require('fs');
const path = require('path');
const vm = require('vm');

class APIGateway {
  constructor(config = {}) {
    this.port = config.port || 3000;
    this.plugins = [];
    this.routes = config.routes || {};
    this.loadPlugins(config.plugins || []);
  }

  loadPlugins(pluginConfigs) {
    pluginConfigs.forEach(pluginConfig => {
      try {
        let plugin;
        
        if (pluginConfig.type === 'file') {
          const pluginPath = path.resolve(pluginConfig.path);
          delete require.cache[require.resolve(pluginPath)];
          plugin = require(pluginPath);
        } else if (pluginConfig.type === 'code') {
          plugin = eval(`(${pluginConfig.code})`);
        } else if (pluginConfig.type === 'eval') {
          const exports = {};
          eval(pluginConfig.code);
          plugin = exports.default || exports;
        } else if (pluginConfig.type === 'vm') {
          const sandbox = {
            require: require,
            console: console,
            module: { exports: {} },
            exports: {}
          };
          vm.runInNewContext(pluginConfig.code, sandbox);
          plugin = sandbox.module.exports.default || sandbox.module.exports;
        } else if (pluginConfig.type === 'env') {
          const envCode = process.env[pluginConfig.envVar];
          if (envCode) {
            plugin = eval(`(${envCode})`);
          }
        }

        if (plugin && typeof plugin === 'function') {
          this.plugins.push({
            name: pluginConfig.name || 'anonymous',
            handler: plugin,
            priority: pluginConfig.priority || 0,
            stage: pluginConfig.stage || 'all'
          });
        } else if (plugin && typeof plugin === 'object') {
          this.plugins.push({
            name: pluginConfig.name || 'anonymous',
            handler: plugin,
            priority: pluginConfig.priority || 0,
            stage: pluginConfig.stage || 'all'
          });
        }
      } catch (error) {
        console.error(`Failed to load plugin ${pluginConfig.name}:`, error);
      }
    });

    this.plugins.sort((a, b) => b.priority - a.priority);
  }

  async executePlugins(stage, context) {
    const stagePlugins = this.plugins.filter(p => p.stage === stage || p.stage === 'all');
    
    for (const plugin of stagePlugins) {
      try {
        if (typeof plugin.handler === 'function') {
          const result = await plugin.handler(context);
          if (result !== undefined) {
            Object.assign(context, result);
          }
        } else if (plugin.handler[stage]) {
          const result = await plugin.handler[stage](context);
          if (result !== undefined) {
            Object.assign(context, result);
          }
        }
        
        if (context.stopPropagation) {
          break;
        }
      } catch (error) {
        console.error(`Plugin ${plugin.name} error:`, error);
        if (context.throwOnError) {
          throw error;
        }
      }
    }
    
    return context;
  }

  async proxyRequest(targetUrl, context) {
    return new Promise((resolve, reject) => {
      const parsedUrl = url.parse(targetUrl);
      const protocol = parsedUrl.protocol === 'https:' ? https : http;
      
      const options = {
        hostname: parsedUrl.hostname,
        port: parsedUrl.port,
        path: parsedUrl.path,
        method: context.request.method,
        headers: context.request.headers
      };

      const proxyReq = protocol.request(options, (proxyRes) => {
        let data = Buffer.alloc(0);
        
        proxyRes.on('data', (chunk) => {
          data = Buffer.concat([data, chunk]);
        });
        
        proxyRes.on('end', () => {
          context.response.statusCode = proxyRes.statusCode;
          context.response.headers = proxyRes.headers;
          context.response.body = data;
          resolve(context);
        });
      });

      proxyReq.on('error', (error) => {
        reject(error);
      });

      if (context.request.body) {
        proxyReq.write(context.request.body);
      }
      
      proxyReq.end();
    });
  }

  async handleRequest(req, res) {
    const parsedUrl = url.parse(req.url, true);
    let body = Buffer.alloc(0);

    for await (const chunk of req) {
      body = Buffer.concat([body, chunk]);
    }

    const context = {
      request: {
        method: req.method,
        url: req.url,
        path: parsedUrl.pathname,
        query: parsedUrl.query,
        headers: req.headers,
        body: body,
        rawRequest: req
      },
      response: {
        statusCode: 200,
        headers: {},
        body: null,
        rawResponse: res
      },
      state: {},
      stopPropagation: false,
      throwOnError: false
    };

    try {
      await this.executePlugins('preRequest', context);
      
      if (!context.response.body && !context.stopPropagation) {
        const route = this.routes[context.request.path];
        if (route) {
          await this.proxyRequest(route.target, context);
        } else {
          context.response.statusCode = 404;
          context.response.body = Buffer.from(JSON.stringify({ error: 'Route not found' }));
        }
      }

      await this.executePlugins('postRequest', context);

      res.writeHead(context.response.statusCode, context.response.headers);
      res.end(context.response.body);
    } catch (error) {
      console.error('Request handling error:', error);
      res.writeHead(500, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Internal Server Error', message: error.message }));
    }
  }

  start() {
    const server = http.createServer((req, res) => this.handleRequest(req, res));
    
    server.listen(this.port, () => {
      console.log(`API Gateway running on port ${this.port}`);
      console.log(`Loaded ${this.plugins.length} plugins`);
    });
    
    return server;
  }
}

